import { Component, signal } from '@angular/core';
import { AXRruleComponent } from '@acorex/components/rrule';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive RRule Builder</h2>
      <ax-rrule 
        [value]="rruleValue()"
        (valueChange)="onValueChange($event)"
        (rruleChange)="onRruleChange($event)"
        (stringChange)="onStringChange($event)"
        (textChange)="onTextChange($event)"
      />
      <div class="rrule-info">
        <p><strong>Generated Dates:</strong> {{ generatedDates().length }} occurrences</p>
        <p><strong>Human Readable:</strong> {{ humanReadableText() }}</p>
      </div>
    </div>
  `,
  imports: [AXRruleComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
    }
    .rrule-info {
      margin-top: 1rem;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class RRuleShowcaseComponent {
  rruleValue = signal<string>('RRULE:FREQ=WEEKLY;INTERVAL=1;WKST=MO;COUNT=5');
  generatedDates = signal<Date[]>([]);
  humanReadableText = signal<string>('');

  onValueChange(value: any): void {
    console.log('Value changed:', value);
  }

  onRruleChange(rrule: any): void {
    if (rrule) {
      try {
        const dates = rrule.all();
        this.generatedDates.set(dates);
      } catch (error) {
        console.error('Error generating dates:', error);
        this.generatedDates.set([]);
      }
    }
  }

  onStringChange(value: string | null): void {
    console.log('RRULE string:', value);
  }

  onTextChange(value: string | null): void {
    this.humanReadableText.set(value || '');
  }
}
